import{o as a,f as m,y as e}from"./framework.2171159c.js";const t='{"title":"Шива махимна стотра","description":"","frontmatter":{"title":"Шива махимна стотра","subtitle":"<p class=\\"sanskrt\\">पशिवमहिम्नः स्तोत्रम्</p> <p class=\\"transcript\\">Śivamahimnaḥ stotram</p>Гимн величия Шивы","tags":"hymn"},"relativePath":"hymns/mahimna/index.md","lastUpdated":1624803860378}',r={},i=e('<p><a href="https://www.sanskrit-trikashaivism.com/ru/shiva-mahimna-stotram-normal-translation-ru/597" class="external-link" target="_blank" rel="noopener noreferrer">Перевод на русский Ирины Валлабхи с английского и испанского пословного перевода Гуру Габриэля Прадиипаки</a></p><p>[sect]</p><p>[sans]गजाननं भूतगणाधिसेवितं कपित्थजम्बूफलचारुभक्षणम्। उमासुतं शोकविनाशकारकं नमामि विघ्नेश्वरपादपङ्कजम्॥[/sans] [trans]Gajānanaṁ bhūtagaṇādisevitaṁ kapitthajambūphalacārubhakṣanam| Umāsutaṁ śokavināśakārakaṁ namāmi vighneśvarapādapaṅkajam||[/trans] Я преклоняюсь <em>(namāmi)</em> перед лотосными стопами <em>(pādapaṅkajam)</em> Господа <em>(īśvara)</em>, [который избавляет от] препятствий <em>(vighna)</em> [и] вызывает <em>(kārakam)</em> разрушение <em>(vināśa)</em> [всех] горестей <em>(śoka)</em>, слонолицего <em>(gaja-ānanam)</em> сына <em>(sutam)</em> Умы -- супруги Шивы-- <em>(umā)</em>, которому служат <em>(sevitam)</em> армии <em>(gaṇa)</em> духов и приведений <em>(bhūta)</em> [Шивы], и т.д. <em>(ādi)</em> и который очаровательно <em>(cāru)</em> вкушает <em>(bhakṣaṇam)</em> дикие яблоки <em>(kapittha... phala)</em> и розовые яблоки <em>(jambūphala)</em>.</p><p>[/sect] [sect]</p><p>[sans]श्रीपुष्पदन्त उवाच महिम्नः पारं ते परमविदुषो यद्यसदृशी स्तुतिर्ब्रह्मादीनामपि तदवसन्नास्त्वयि गिरः। अथावाच्यः सर्वः स्वमतिपरिणामावधि गृणन् ममाप्येषः स्तोत्रे हर निरपवादः परिकरः॥१॥[/sans] [trans]Śrīpuṣpadanta uvāca Mahimnaḥ pāraṁ te paramaviduṣo yadyasadṛśī stutirbrahmādīnāmapi tadavasannāstvayi giraḥ| Athāvācyaḥ sarvaḥ svamatipariṇāmāvadhi gṛṇan mamāpyeṣaḥ stotre hara nirapavādaḥ parikaraḥ||1||[/trans] Почтенный <em>(śrī)</em> Пушпаданта --досл. «с зубами из цветов»-- <em>(puṣpadantaḥ)</em> сказал <em>(uvāca)</em>:</p><p>Если бы <em>(yadi)</em> восхваление <em>(stutiḥ)</em>, [выполненное] кем-то, кто совсем <em>(param)</em> не знает <em>(avidusaḥ)</em> предела <em>(pāram)</em> Твоего <em>(te)</em> величия <em>(mahimnaḥ)</em>, было бы неподобающе <em>(asadṛśī)</em>, тогда <em>(tad)</em> даже <em>(api)</em> возгласы восхваления <em>(giraḥ)</em> Тебя <em>(tvayi)</em>, [произнесённые] Брахмой _(brahmā)_и т.д., --ādi-- <em>(ādīnām)</em> [были бы] отклонены и увяли бы <em>(avasannāḥ)</em>. К тому же <em>(atha)</em>, [если] все <em>(sarvaḥ)</em>, кто восхваляет [Тебя] _(gṛṇan)<em>согласно <em>(avadhi)</em> развитости <em>(pariṇāma)</em> своего <em>(sva)</em> разума <em>(mati)</em> не могут быть обвинены или оговорены <em>(avācyaḥ)</em>, [тогда], о Хара --Шива-- <em>(hara)</em>, этот <em>(eṣaḥ)</em> «Парикара» --ряд эпитетов или прилагательных-- [в честь Тебя] <em>(parikaraḥ)</em>, [написанных] мною <em>(mama)</em> в гимне <em>(stotre)</em>, тоже</em> <em>(api)</em> не может быть подвергнут цензуре <em>(nirapavādaḥ)</em>||1||</p><p>[/sect] [sect] [sans]अतीतः पन्थानं तव च महिमा वाङ्मानसयोरतद्व्यावृत्त्या यं चकितमभिधत्ते श्रुतिरपि। स कस्य स्तोतव्यः कतिविधगुणः कस्य विषयः पदे त्वर्वाचीने पतति न मनः कस्य न वचः॥२॥[/sans] [trans]Atītaḥ panthānaṁ tava ca mahimā vāṅmānasayoratadvyāvṛttyā yaṁ cakitamabhidhatte śrutirapi| Sa kasya stotavyaḥ katividhaguṇaḥ kasya viṣayaḥ pade tvarvācīne patati na manaḥ kasya na vacaḥ||2||[/trans] Твое <em>(tava)</em> величие <em>(mahimā)</em> определённо <em>(ca)</em> вне <em>(atītaḥ)</em> досягаемости <em>(panthānam)</em> речи <em>(vāk)</em> и ума --mānasa-- <em>(mānasayoḥ)</em>. Даже <em>(api)</em> Шрути -- этот термин обычно является синонимом Вед, хотя он должен быть использован только по отношению к разделам «Mantra» и «Brāhmaṇa» вышеупомянутых Вед-- <em>(śrutiḥ)</em> с благоговением <em>(cakitam)</em> описывает <em>(abhidhatte)</em> то [величие] <em>(yam)</em>, за исключением [любых других имён] <em>(vyāvṛttyā)</em>, [таких как] «не то» <em>(atad)</em>. [Итак], кем <em>(kasya)</em> Он --Шива-- <em>(saḥ)</em> [будет] восхваляться <em>(stotavyaḥ)</em>? Сколькими <em>(katividha)</em> качествами <em>(guṇa)</em> [обладает Шива]? Кем <em>(kasya)</em> [Он будет] воспринят <em>(viṣayaḥ)</em>? Тем не менее <em>(tu)</em>, [где тот человек], чьи <em>(kasya)</em> ум <em>(manas)</em> [и] речь <em>(vacaḥ)</em> не <em>(na... na)</em> пропадают <em>(patati)</em> при состоянии <em>(pade)</em>, в которое [Ты] входишь после <em>(arvācīne)</em>?||2||</p><p>[/sect] [sect] [sans]मधुस्फीता वाचः परमममृतं निर्मितवतस्तव ब्रह्मन्किं वागपि सुरगुरोर्विस्मयपदम्। मम त्वेनां वाणीं गुणकथनपुण्येन भवतः पुनामीत्यर्थेऽस्मिन् पुरमथन बुद्धिर्व्यवसिता॥३॥[/sans] [trans]Madhusphītā vācaḥ paramamamṛtaṁ nirmitavatastava brahmankiṁ vāgapi suragurorvismayapadam| Mama tvenāṁ vāṇīṁ guṇakathanapuṇyena bhavataḥ punāmītyarthe&#39;smin puramathana buddhirvyavasitā||3||[/trans]</p><p>О, Брахма --Абсолют-- <em>(brahman)</em>! Удивительно ли <em>(kim... vismayapadam)</em>, что даже <em>(api)</em> гуру --наставник-- <em>(guroḥ)</em> богов <em>(sura)</em> --т.e. «Bṛhaspati»-- [произнёс] слова <em>(vāk)</em> [восхваляющие] Тебя <em>(tava)</em>, автора --nirmitavān-- <em>(nirmitavataḥ)</em> Высшего <em>(paramam)</em> Нектара <em>(amṛtam)</em> --т.e. Вед--, состоящего из слов <em>(vācaḥ)</em> полных <em>(sphītāḥ)</em> мёда [знания] <em>(madhu)</em>? «Я несомненно <em>(tu)</em> отчищаю <em>(punāmi)</em> мою <em>(mama... enām)</em> речь <em>(vāṇīm)</em> благодетельным актом <em>(puṇyena)</em> описания <em>(kathana)</em> Твоих <em>(bhavataḥ)</em> качеств <em>(guṇa)</em>»... Для этой цели <em>(ityarthe)</em>, [мой] разум <em>(buddhiḥ)</em> решительно принял на себя <em>(vyavasitā)</em> эту [задачу] <em>(asmin)</em>, о Разрушитель <em>(mathana)</em> [трёх] городов <em>(pura)</em>! --Шиву называют «puramathana», потому что Он разрушил три города, принадлежащих трём сыновьям демонов по имени Tāraka--||3||</p><p>[/sect] [sect] [sans]तवैश्वर्यं यत्तज्जगदुदयरक्षाप्रलयकृत्त्रयीवस्तु व्यस्तं तिसृषु गुणभिन्नासु तनुषु। अभव्यानामस्मिन् वरद रमणीयामरमणीं विहन्तुं व्याक्रोशीं विदधत इहैके जडधियः॥४॥[/sans] [trans]Tavaiśvaryaṁ yattajjagadudayarakṣāpralayakṛttrayīvastu vyastaṁ tisṛṣu guṇabhinnāsu tanuṣu| Abhavyānāmasmin varada ramaṇīyāmaramaṇīṁ vihantuṁ vyākrośīṁ vidadhata ihaike jaḍadhiyaḥ||4||[/trans]</p><p>Твой <em>(tava)</em> Суверенитет или Господсво <em>(aiśvaryam)</em>, который <em>(yad-tad)</em> [состоит из] «того, что вызывает <em>(kṛt)</em> проявление <em>(udaya)</em> мира <em>(jagat)</em>» --т.e. Brahmā--, «того, что даёт <em>(kṛt)</em> защиту <em>(rakṣā)</em> миру <em>(jagat)</em>» --т.e. Viṣṇu--, «того, что является причиной <em>(kṛt)</em> растворения <em>(pralaya)</em> мира <em>(jagat)</em>» --т.e. Rudra--, обладает трехкратной <em>(trayī)</em> сутью <em>(vastu)</em>, которая классифицирована [в Ведах] <em>(vyastam)</em> согласно тройственной <em>(tisṛṣu)</em> форме <em>(tanuṣu)</em>, состоящей из разных <em>(bhinnāsu)</em> гун --качеств Prakṛti-- <em>(guṇa)</em>. О дарующий <em>(da)</em> милость <em>(vara)</em>! В этом мире <em>(iha)</em> некоторые <em>(eke)</em> слабоумные люди <em>(jaḍadhiyaḥ)</em> приводят <em>(vidadhate)</em> оскорбительные <em>(vyākrośīm)</em> <em>(и)</em> неприятные <em>(aramaṇīm)</em> <em>(доводы),</em> чтобы докучать <em>(vihantum)</em>. [Этими аргументами] наслаждаются [только] <em>(ramaṇīyām)</em> безбожные и непосвящённые <em>(abhavyānām)</em> в это <em>(asmin)</em> --т.e. «в истину Суверенитета или Господства Шивы»--||4||</p><p>[/sect] [sect] [sans]किमीहः किंकायः स खलु किमुपायस्त्रिभुवनं किमाधारो धाता सृजति किमुपादान इति च। अतर्क्यैश्वर्ये त्वय्यनवसरदुःस्थो हतधियः कुतर्कोऽयं कांश्चिन्मुखरयति मोहाय जगतः॥५॥[/sans] [trans]Kimīhaḥ kiṅkāyaḥ sa khalu kimupāyastribhuvanaṁ kimādhāro dhātā sṛjati kimupādāna iti ca| Atarkyaiśvarye tvayyanavasaraduḥstho hatadhiyaḥ kutarko&#39;yaṁ kāṁścinmukharayati mohāya jagataḥ||5||[/trans] «Какое <em>(kim)</em> желание <em>(īhaḥ)</em> Он [удовлетворяет] <em>(saḥ khalu)</em>? В каком <em>(kim)</em> теле <em>(kāyaḥ)</em> Он [воплощается] <em>(saḥ khalu)</em>? [И] какой <em>(kim)</em> метод <em>(upāyaḥ)</em>, основу <em>(ādhāraḥ)</em> и материал <em>(upadānaḥ)</em> Создатель <em>(dhātā)</em> [использует для] проявления <em>(sṛjati)</em> трёх <em>(tri)</em> миров <em>(bhuvanam... iti ca)</em>?» --«iti» означает кавычки, а «ca» является всего лишь вставным элементом в этом случае--. Этот <em>(ayam)</em> ошибочный образ аргументирования <em>(kutarkaḥ)</em>, немудрый <em>(duḥsthaḥ)</em> и неуместный <em>(anavasara)</em>, в отношении Тебя <em>(tvayi)</em> и [Твоего] Суверенитета или Господства <em>(aiśvarye)</em>, который превосходит мышление и логику <em>(atarkya)</em>, [происходит] от сбитой с толку личности <em>(hatadhiyaḥ)</em>. [Этот самый ошибочный образ аргументирования] заставляет некоторых людей <em>(kān-cid)</em> [громко] говорить <em>(mukharayati)</em> [только лишь для того], чтобы мир <em>(jagataḥ)</em> утратил осознанность и пал жертвой заблуждения <em>(mohāya)</em>||5||</p><p>[/sect] [sect] [sans]अजन्मानो लोकाः किमवयववन्तोऽपि जगतामधिष्टातारं किं भवविधिरनादृत्य भवति। अनीशो वा कुर्याद्भुवनजनने कः परिकरो यतो मन्दास्त्वां प्रत्यमरवर संशेरत इमे॥६॥[/sans] [trans]Ajanmāno lokāḥ kimavayavavanto&#39;pi jagatāmadhiṣṭhātāraṁ kiṁ bhavavidhiranādṛtya bhavati| Anīśo vā kuryādbhuvanajanane kaḥ parikaro yato mandāstvāṁ pratyamaravara saṁśerata ime||6||[/trans] «Существуют ли <em>(kim)</em> миры <em>(lokāḥ)</em> без какого либо источника <em>(ajanmānaḥ)</em>, не смотря на то, что <em>(api)</em> они состоят из частей <em>(avayavavantaḥ)</em>? Имеет ли место быть <em>(kim... bhavati)</em> создание <em>(vidhiḥ)</em> миров <em>(bhava)</em> вне зависимости <em>(anādṛtya)</em> _от _[существования] кого-то, кто правит <em>(adhiṣṭhātāram)</em> [вышеупомянутыми] мирами <em>(jagatām)</em>? Или <em>(vā)</em>, <em>(если)</em> Господина не существует <em>(anīśaḥ)</em>, какой <em>(kaḥ)</em> помощник <em>(parikaraḥ)</em> содействует <em>(kuryāt)</em> в проявлении <em>(janane)</em> миров <em>(bhuvana)</em>?» Основывая [свои идеи] на [подобном образе мышления] <em>(yatas)</em>, о Ты, высший <em>(vara)</em> среди богов <em>(amara)</em>, эти <em>(ime)</em> слабоумные и глупые личности <em>(mandāḥ)</em> вызывают сомнения <em>(saṁśerate)</em> о Тебе <em>(tvāṁ prati)</em>||6||</p><p>[/sect] [sect] [sans]त्रयी साङ्ख्यं योगः पशुपतिमतं वैष्णवमिति प्रभिन्ने प्रस्थाने परमिदमदः पथ्यमिति च। रुचीनां वैचित्र्यादृजुकुटिलनानापथजुषां नृणामेको गम्यस्त्वमसि पयसामर्णव इव॥७॥[/sans] [trans]Trayī sāṅkhyaṁ yogaḥ paśupatimataṁ vaiṣṇavamiti prabhinne prasthāne paramidamadaḥ pathyamiti ca| Rucīnāṁ vaicitryādṛjukuṭilanānāpathajuṣāṁ nṛṇāmeko gamyastvamasi payasāmarṇava iva||7||[/trans] «Три Веды <em>(trayī)</em>, Санкхья <em>(sāṅkhyam)</em>, Йога <em>(yogaḥ)</em>, учение <em>(matam)</em> Пашупати <em>(paśupati)</em> --т.e. Шиваизм-- <em>(и)</em> Вайшнавизм -- относящийся к Господу Вишну-- <em>(vaiṣṇavam iti)</em>»: в [этих] разных <em>(prabhinne)</em> источниках <em>(prasthāne)</em> таким образом [содержится] <em>(iti ca)</em> тот <em>(idam)</em> или иной <em>(adas)</em> путь <em>(pathyam)</em> к Высшему [Состоянию] <em>(param)</em> --т.e. есть разные способы осознания Высшего Я или Шивы--. Для людей <em>(nṛṇām)</em>, преданных <em>(juṣām)</em> различным <em>(nānā)</em> путям <em>(patha)</em>, прямым и извилистым <em>(ṛju-kuṭila)</em>, согласно разнообразию <em>(vaicitryāt)</em> их аппетитов <em>(rucīnām)</em>, Ты <em>(tvam)</em> являешься <em>(asi)</em> единственной <em>(ekaḥ)</em> целью для достижения <em>(gamyaḥ)</em>, подобно тому, чем <em>(iva)</em> океан [является] <em>(arṇavaḥ)</em> для вод <em>(payasām)</em> --т.e. воды рек, дождь и т.д. в результате впадают в океан--||7||</p><p>[/sect] [sect] [sans]महोक्षः खट्वाङ्गं परशुरजिनं भस्म फणिनः कपालं चेतीयत्तव वरद तन्त्रोपकरणम्। सुरास्तां तामृद्धिं दधति तु भवद्भ्रप्रणिहितां न हि स्वात्मारामं विषयमृगतृष्णा भ्रमयति॥८॥[/sans] [trans]Mahokṣaḥ khaṭvāṅgaṁ paraśurajinaṁ bhasma phaṇinaḥ kapālaṁ cetīyattava varada tantropakaraṇam| Surāstāṁ tāmṛddhiṁ dadhati tu bhavadbhrapraṇihitāṁ na hi svātmārāmaṁ viṣayamṛgatṛṣṇā bhramayati||8||[/trans] «Крупный <em>(mahā)</em> бык <em>(ukṣaḥ)</em>, посох в форме остова кровати --т.e. посох с черепом на конце-- <em>(khaṭvāṅgam)</em>, томагавк <em>(paraśuḥ)</em>, шкура тигра <em>(ajinam)</em>, пепел <em>(bhasma)</em>, кобры с раздутыми капюшонами <em>(phaṇinaḥ)</em> и <em>(ca)</em> череп <em>(kapālam... iti)</em>» -- iti означает кавычки--: только эти предметы <em>(iyat)</em> являются Твоей <em>(tava)</em> основной характерной <em>(tantra)</em> утварью <em>(upakaraṇam)</em>, о Дарующий <em>(da)</em> милость <em>(vara)</em>! Тем не менее <em>(tu)</em>, боги <em>(surāḥ)</em> получают <em>(dadhati)</em> различные <em>(tām tām)</em> «риддхи» --т.e. процветание, богатство, успех и т.д.-- <em>(ṛddhim)</em>, [появляющиеся как результат] Твоей <em>(bhavat)</em> концентрации <em>(praṇihitām)</em> на [области между] бровями <em>(bhra)</em>. Несомненно <em>(hi)</em>, мираж <em>(mṛgatṛṣṇā)</em> из объектов <em>(viṣaya)</em> не <em>(na)</em> волнует <em>(bhramayati)</em> того, кто наслаждается <em>(ārāmam)</em> своим <em>(sva)</em> Высшим Я <em>(ātma)</em>||8||</p><p>[/sect] [sect] [sans]ध्रुवं कश्चित् सर्वं सकलमपरस्त्वध्रुवमिदं परो ध्रौव्याध्रौव्ये जगति गदति व्यस्तविषये। समस्तेऽप्येतस्मिन् पुरमथन तैर्विस्मित इव स्तुवञ्जिह्रेमि त्वां न खलु ननु धृष्टा मुखरता॥९॥[/sans] [trans]Dhruvaṁ kaścit sarvaṁ sakalamaparastvadhruvamidaṁ paro dhrauvyādhrauvye jagati gadati vyastaviṣaye| Samaste&#39;pyetasmin puramathana tairvismita iva stuvañjihremi tvāṁ na khalu nanu dhṛṣṭā mukharatā||9||[/trans] Некоторые <em>(kaścid)</em> [утверждают, что] всё <em>(sarvam)</em> вечно <em>(dhruvam)</em>. Тем не менее <em>(tu)</em>, другие <em>(aparaḥ)</em> [говорят, что] всё <em>(sakalam)</em> это <em>(idam)</em> не вечно <em>(adhruvam)</em>. [В свою очередь] третьи <em>(paraḥ)</em> провозглашают <em>(gadati)</em> в отношении этого мира <em>(jagati)</em>, состоящего из различных <em>(vyasta)</em> объектов и качеств <em>(viṣaye)</em>, что он как вечный <em>(dhrauvya)</em>, так и эфемерный --adhrauvya-- <em>(adhrauvye)</em>. О Разрушитель <em>(mathana)</em> <em>(трёх)</em> городов <em>(pura)</em>! Удивлённый <em>(vismitaḥ)</em>, так сказать <em>(iva)</em>, всеми этими [точками зрения] <em>(taiḥ)</em> в отношении всего <em>(samaste)</em> этого <em>(Создания)</em> <em>(api etasmin)</em>, Я не стыжусь <em>(jihremi... na)</em> восхвалять <em>(stuvan)</em> Тебя <em>(tvām)</em>... [Моя] разговорчивость <em>(mukharatā)</em> действительно <em>(khalu nanu)</em> дерзка <em>(dhṛṣṭā)</em>!||9||</p><p>[/sect] [sect] [sans]तवैश्वर्यं यत्नाद्यदुपरि विरिञ्चिर्हरिरधः परिच्छेत्तुं यातावनलमनलस्कन्धवपुषः। ततो भक्तिश्रद्धाभरगुरुगृणद्भ्यां गिरिश यत्स्वयं तस्थे ताभ्यां तव किमनुवृत्तिर्न फलति॥१०॥[/sans] [trans]Tavaiśvaryaṁ yatnādyadupari viriñcirhariradhaḥ paricchetuṁ yātāvanalamanalaskandhavapuṣaḥ| Tato bhaktiśraddhābharagurugṛṇadbhyāṁ girīśa yatsvayaṁ tasthe tābhyāṁ tava kimanuvṛttirna phalati||10||[/trans] Brahmā --Создатель-- <em>(viriñciḥ)</em> сверху <em>(yad-upari)</em> <em>(и)</em> Viṣṇu --Поддерживающий-- <em>(hariḥ)</em> снизу <em>(adhas)</em> продолжили <em>(yātau)</em> с усилием <em>(yatnāt)</em> точно определять <em>(paricchettum)</em> Твой <em>(tava)</em> Суверенитет или Господство <em>(aiśvaryam)</em>, [когда Ты принял] форму <em>(vapuṣaḥ)</em> огненного <em>(anala)</em> столба <em>(skandha)</em>, [но] этого было недостаточно --т.e. у них ничего не получилось-- <em>(analam)</em>. [Тем не менее] потом <em>(tatas)</em>, [только] когда они оба восхваляли [Шиву] <em>(gṛṇadbhyām)</em> в высшей степени <em>(guru)</em> с <em>(bhara)</em> преданностью <em>(bhakti)</em> и верой <em>(śraddhā)</em>, о Girīśa --т.e. «Горный Господь», эпитет Шивы-- <em>(giri-īśa)</em>, тогда <em>(yad)</em> Он --Шива-- показал <em>(tasthe)</em> Его [сущностную природу] <em>(svayam)</em> им обоим <em>(tābhyām)</em>. Какое <em>(kim)</em> уважительное действие <em>(anuvṛttiḥ)</em> в честь Тебя <em>(tava)</em> [подобное тому, которое выполнили Брахмаа и Вишну] не принесёт [в конце концов] плодов?||10||</p><p>[/sect] [sect] [sans]अयत्नादापाद्य त्रिभुवनमवैरव्यतिकरं दशास्यो यद्बाहूनभृत रणकण्डूपरवशान्। शिरःपद्मश्रेणीरचितचरणाम्भोरुहबलेः स्थिरायास्त्वद्भक्तेस्त्रिपुरहर विस्फूर्जितमिदम्॥११॥[/sans] [trans]Ayatnādāpādya tribhuvanamavairavyatikaraṁ daśāsyo yadbāhūnabhṛta raṇakaṇḍūparavaśān| Śiraḥpadmaśreṇīracitacaraṇāmbhoruhabaleḥ sthirāyāstvadbhaktestripurahara visphūrjitamidam||11||[/trans] Без усилий <em>(ayatnāt)</em> избавившись от всего вражеского проникновения --т.e. от всех врагов из трёх миров-- досл. «приведя <em>(āpādya)</em> три <em>(tri)</em> мира <em>(bhuvanam)</em> в состояние без <em>(a)</em> какого-либо вражеского <em>(vaira)</em> проникновения <em>(vyatikaram)</em> »-- <em>(āpādya tribhuvanam avairavyatikaram)</em>, у [демона] с десятью ртами --Rāvaṇa, известного врага Rāmacandra-- <em>(daśa-āsyaḥ)</em> его <em>(yad)</em> <em>(двадцать)</em> рук <em>(bāhūn... abhṛta)</em> <em>(всё ещё)</em> одолевало <em>(paravaśān)</em> желание --досл. «они чесались»-- <em>(kaṇḍū)</em> сражения <em>(raṇa)</em>. [После этого], о Разрушитель <em>(hara)</em> трёх <em>(tri)</em> городов <em>(pura)</em>!, <em>(Rāvaṇa)</em> сложил <em>(racita)</em> в ряд <em>(śreṇī)</em> [его десять] лотосных голов <em>(śiras-padma)</em> в виде подношения --bali-- <em>(baleḥ)</em> к [Твоим] стопам <em>(caraṇa)</em>, [прекрасным] как лотос <em>(ambhoruha)</em>. [Он сделал это] из-за [своей] непоколебимой <em>(sthirāyāḥ)</em> преданности <em>(bhakteḥ)</em> Тебе <em>(tvat)</em>. Этот [акт сдачи] <em>(idam)</em> случился спонтанно <em>(visphūrjitam)</em>||11||</p><p>[/sect] [sect] [sans]अमुष्य त्वत्सेवासमधिगतसारं भुजवनं बलात्कैलासेऽपि त्वदधिवसतौ विक्रमयतः। अलभ्या पातालेऽप्यलसचलिताङ्गुष्ठशिरसि प्रतिष्ठा त्वय्यासीद्ध्रुवमुपचितो मुह्यति खलः॥१२॥[/sans] [trans]Amuṣya tvatsevāsamadhigatasāraṁ bhujavanaṁ balātkailāse&#39;pi tvadadhivasatau vikramayataḥ| Alabhyā pātāle&#39;pyalasacalitāṅguṣṭhaśirasi pratiṣṭhā tvayyāsīddhruvamupacito muhyati khalaḥ||12||[/trans] [Тем не менее,] для этого [самого демона] <em>(amuṣya)</em> не находилось <em>(alabhyā... āsīt)</em> места покоя <em>(pratiṣṭhā)</em> даже <em>(api)</em> в низшем аду --или в «низшей области»-- <em>(pātāle)</em> когда (Ты) праздно <em>(alasa)</em> пошевелил <em>(calita)</em> кончиком --śiras-- <em>(śirasi)</em> Твоего --tava-- <em>(tvayi)</em> великого пальца ноги <em>(aṅguṣṭha)</em>, (потому что он) также <em>(api)</em> [ранее] отправился маршем <em>(vikramayataḥ)</em> на Кайласу <em>(kailāse)</em>, Твою <em>(tvat)</em> Обитель --adhivasati-- <em>(adhivasatau)</em>, <em>(в попытке захватить её)</em> силой <em>(balāt)</em> его [бесчисленных] рук <em>(bhuja)</em>, похожих на лес <em>(vanam)</em>, чья сила <em>(sāram)</em> была достигнута <em>(samadhigatam)</em> служением <em>(sevā)</em> Тебе <em>(tvat)</em>. Однозначно <em>(dhruvam)</em>, бесшабашный человек <em>(khalaḥ)</em> впадает в заблуждение <em>(muhyati)</em> из-за богатства <em>(upacitaḥ)</em>||12||</p><p>[/sect] [sect] [sans]यदृद्धिं सुत्राम्णो वरद परमोच्चैरपि सतीमधश्चक्रे बाणः परिजनविधेयत्रिभुवनः। न तच्चित्रं तस्मिन्वरिवसितरि त्वच्चरणयोर्न कस्या उन्नत्यै भवति शिरसस्त्वय्यवनतिः॥१३॥[/sans] [trans]Yadṛddhiṁ sutrāmṇo varada paramoccairapi satīmadhaścakre bāṇaḥ parijanavidheyatribhuvanaḥ| Na taccitraṁ tasminvarivasitari tvaccaraṇayorna kasyā unnatyai bhavati śirasastvayyavanatiḥ||13||[/trans] О дарующий <em>(da)</em> милость <em>(vara)</em>! Что касается <em>(yad)</em> Bāṇa <em>(bāṇaḥ)</em>, который превратил три <em>(tri)</em> мира <em>(bhuvanaḥ)</em> в послушных <em>(vidheya)</em> слуг <em>(parijana)</em>, [он наслаждался] даже <em>(api)</em> богатством <em>(ṛddhim)</em> Сутраамана --эпитет Индры, бога рая, означающий «хорошо защищающий»-- <em>(sutrāmṇaḥ)</em>, которое является <em>(satīm)</em> крайне <em>(uccais)</em> превосходным <em>(parama)</em> в нижней <em>(adhas)</em> реалии, [которой он правил как царь] <em>(cakre)</em>. Это <em>(tad)</em> (совсем) не <em>(na)</em> удивительно <em>(citram)</em>, [потому что] тот [царь демонов] <em>(tasmin)</em> поклонялся <em>(varivasitari)</em> Твоим <em>(tvat)</em> стопам <em>(caraṇayoḥ)</em>. К какому богатству <em>(kasyai unnatyai)</em> склонение <em>(avanatiḥ)</em> <em>(своей)</em> головы <em>(śirasaḥ)</em> перед Тобой <em>(tvayi)</em> не <em>(na)</em> приведёт <em>(bhavati)</em>? --т.e. не существует богатства, недоступного тому, кто склоняет свою голову перед Тобой--||13||</p><p>[/sect] [sect] [sans]अकाण्डब्रह्माण्डक्षयचकितदेवासुरकृपाविधेयस्यासीद्यस्त्रिनयन विषं संहृतवतः। स कल्माषः कण्ठे तव न कुरुते न श्रियमहो विकारोऽपि श्लाघ्यो भुवनभयभङ्गव्यसनिनः॥१४॥[/sans] [trans]Akāṇḍabrahmāṇḍakṣayacakitadevāsurakṛpāvidheyasyāsīdyastrinayana viṣaṁ saṁhṛtavataḥ| Sa kalmāṣaḥ kaṇṭhe tava na kurute na śriyamaho vikāro&#39;pi ślāghyo bhuvanabhayabhaṅgavyasaninaḥ||14||[/trans] О Трёхглазый <em>(trinayana)</em>! То <em>(saḥ)</em> [синее] пятно <em>(kalmāṣaḥ)</em> на Твоём <em>(tava)</em> горле <em>(kaṇṭhe)</em>, которое <em>(yaḥ)</em> появилось <em>(āsīt)</em> потому что [Ты] удержал [там] <em>(saṁhṛtavataḥ)</em> яд [известный как <em>Kālakūṭa</em>] <em>(viṣam)</em>, когда был охвачен <em>(vidheyasya)</em> состраданием <em>(kṛpā)</em> к богам <em>(deva)</em> и демонам <em>(asura)</em>, напуганным <em>(cakita)</em> неожиданным <em>(akāṇḍa)</em> разрушением <em>(kṣaya)</em> вселенной <em>(brahmāṇḍa)</em>, определённо <em>(na... na)</em> украшает [Тебя] <em>(kurute...śriyam)</em>. Ах <em>(aho)</em>! Даже <em>(api)</em> [вышеупомянутое] изменение в теле <em>(vikāraḥ)</em> того [Верховного Божества], которое обожает <em>(vyasaninaḥ)</em> рассеивать <em>(bhaṅga)</em> страх <em>(bhaya)</em> во всём мире <em>(bhuvana)</em>, достойно восхваления <em>(ślāghyaḥ)</em>||14||</p><p>[/sect] [sect] [sans]असिद्धार्था नैव क्वचिदपि सदेवासुरनरे निवर्तन्ते नित्यं जगति जयिनो यस्य विशिखाः। स पश्यन्नीश त्वामितरसुरसाधारणमभूत्स्मरः स्मर्तव्यात्मा न हि वशिषु पथ्यः परिभवः॥१५॥[/sans] [trans]Asiddhārthā naiva kvacidapi sadevāsuranare nivartante nityaṁ jagati jayino yasya viśikhāḥ| Sa paśyannīśa tvāmitarasurasādhāraṇamabhūtsmaraḥ smartavyātmā na hi vaśiṣu pathyaḥ paribhavaḥ||15||[/trans] О Господь <em>(īśa)</em>! Он --Kāmadeva, бог любви-- <em>(saḥ)</em>, чьи <em>(yasya)</em> стрелы <em>(viśikhāḥ)</em> всегда <em>(nityam)</em> победоносны <em>(jayinaḥ)</em> и не пропускают цели <em>(asiddha-arthāḥ... nivartante)</em> нигде <em>(na eva kvacid-api)</em> в этом мире <em>(jagati)</em>, состоящем <em>(sa)</em> из богов <em>(deva)</em>, демонов <em>(asura)</em> <em>(и)</em> человеческих существ --nara-- <em>(nare)</em>, [просто] считал <em>(paśyan)</em> Тебя <em>(tvām)</em> подобным <em>(sādhāraṇam)</em> более низкому <em>(itara)</em> богу <em>(sura)</em>, и <em>(поэтому)</em> стал <em>(abhūt)</em> воспоминанием <em>(smaraḥ)</em>, живущим [только] в памяти [людей] <em>(smartavya-ātmā)</em>. Несомненно <em>(hi)</em>, оскорбление <em>(paribhavaḥ)</em>, [нанесённое] обуздавшим себя <em>(vaśiṣu)</em>, не <em>(na)</em> приводит к благосостоянию <em>(pathyaḥ)</em>||15||</p><p>[/sect] [sect] [sans]मही पादाघाताद्व्रजति सहसा संशयपदं पदं विष्णोर्भ्राम्यद्भुजपरिघरुग्णग्रहगणम्। मुहुर्द्यौर्दौस्थ्यं यात्यनिभृतजटाताडिततटा जगद्रक्षायै त्वं नटसि ननु वामैव विभुता॥१६॥[/sans] [trans]Mahī pādāghātādvrajati sahasā saṁśayapadaṁ padaṁ viṣṇorbhrāmyadbhujaparigharugṇagrahagaṇam| Muhurdyaurdausthyaṁ yātyanibhṛtajaṭātāḍitataṭā jagadrakṣāyai tvaṁ naṭasi nanu vāmaiva vibhutā||16||[/trans] Из-за удара <em>(āghātāt)</em> [Твоих] стоп <em>(pāda)</em>, земля <em>(mahī)</em> вдруг <em>(sahasā)</em> начинает сомневаться <em>(vrajati... saṁśaya-padam)</em>. [На самом деле все] три мира --досл. «[три] шага Viṣṇu»-- <em>(padam viṣṇoḥ)</em>, которые состоят из множества <em>(gaṇam)</em> планет <em>(graha)</em>, разбитые вдребезги <em>(rugṇa)</em> <em>(Твоими)</em> руками <em>(bhuja)</em>, подобными железным брусьям <em>(parigha)</em>, испытывают смятение <em>(bhrāmyat)</em>. Неожиданно <em>(muhur)</em>, небо <em>(dyaus)</em> становится <em>(yāti)</em> несчастным <em>(dausthyam)</em>, [когда его] покатые края <em>(taṭāḥ)</em> хлыстаются <em>(tāḍita)</em> <em>(Твоими)</em> волнистыми <em>(anibhṛta)</em> скрученными локонами <em>(jaṭā)</em> [во время того, как] Ты <em>(tvam)</em> исполняешь танец <em>(naṭasi)</em> для защиты <em>(rakṣāyai)</em> мира <em>(jagat)</em>. Определённо <em>(eva)</em>, <em>(Твои)</em> Сила и Превосходство <em>(vibhutā)</em> нежелательны [в этот момент] <em>(vāmā)</em>, без сомнений <em>(nanu)</em>||16||</p><p>[/sect] [sect] [sans]वियद्व्यापी तारागणगुणितफेनोद्गमरुचिः प्रवाहो वारां यः पृषतलघुदृष्टः शिरसि ते। जगद्द्वीपाकारं जलधिवलयं तेन कृतमित्यनेनैवोन्नेयं धृतमहिम दिव्यं तव वपुः॥१७॥[/sans] [trans]Viyadvyāpī tārāgaṇaguṇitaphenodgamaruciḥ pravāho vārāṁ yaḥ pṛṣatalaghudṛṣṭaḥ śirasi te| Jagaddvīpākāraṁ jaladhivalayaṁ tena kṛtamityanenaivonneyaṁ dhṛtamahima divyaṁ tava vapuḥ||17||[/trans] Тот <em>(yaḥ)</em> непрекращающийся поток <em>(pravāhaḥ)</em> вод --это эпитет божественной реки по имени «Mandākinī»-- <em>(vārām)</em>, который растекается <em>(vyāpī)</em> по небесам <em>(viyat)</em> [и чья] красота <em>(ruciḥ)</em>, предстающая <em>(udgama)</em> в виде пены <em>(phena)</em>, усиливается <em>(guṇita)</em> множеством <em>(gaṇa)</em> звёзд <em>(tārā)</em>, выглядит <em>(dṛṣṭaḥ)</em> маленькой <em>(laghu)</em> капелькой <em>(pṛṣata)</em> на Твоей <em>(te)</em> голове <em>(śirasi)</em>. Мир <em>(jagat)</em> создаётся <em>(kṛtam)</em> этой самой [священной рекой] <em>(tena)</em> в форме <em>(ākāram)</em> <em>(семи)</em> островов <em>(dvīpa)</em>, окружённых <em>(valayam)</em> океаном <em>(jaladhi)</em>. Таким образом <em>(iti)</em> из этого [заявления] <em>(anena eva)</em> [можно с легкостью] аналогично сделать вывод <em>(unneyam)</em> о Твоей <em>(tava)</em> Божественной <em>(divyam)</em> Форме <em>(vapus)</em>, наделённой постоянным и устойчивым <em>(dhṛta)</em> величием <em>(mahima)</em>||17||</p><p>[/sect] [sect] [sans]रथः क्षोणी यन्ता शतधृतिरगेन्द्रो धनुरथो रथाङ्गे चन्द्रार्कौ रथचरणपाणिः शर इति। दिधक्षोस्ते कोऽयं त्रिपुरतृणमाडम्बरविधिर्विधेयैः क्रीडन्त्यो न खलु परतन्त्राः प्रभुधियः॥१८॥[/sans] [trans]Rathaḥ kṣoṇī yantā śatadhṛtiragendro dhanuratho rathāṅge candrārkau rathacaraṇapāṇiḥ śara iti| Didhakṣoste ko&#39;yaṁ tripuratṛṇamāḍambaravidhirvidheyaiḥ krīḍantyo na khalu paratantrāḥ prabhudhiyaḥ||18||[/trans] [Твоей] колесницей <em>(rathaḥ)</em> <em>(была)</em> земля <em>(kṣoṇī)</em>, колесничим <em>(yantā)</em> <em>(был)</em> Brahmā --также называемый «Śatadhṛti», досл. означает «обладающий сотней жертвоприношений»-- <em>(śatadhṛtiḥ)</em>, гора Меру -- также известная как «Agendra», досл. означает «царь гор»-- <em>(agendraḥ)</em> [была Твоим] луком <em>(dhanus)</em>. Также <em>(atho)</em> двумя колёсами <em>(aṅge)</em> [Твоей] колесницы <em>(rathaḥ)</em> <em>(были)</em> солнце --arka-- и луна --candra-- <em>(candrārkau)</em>. Viṣṇu --называемый «Rathacaraṇapāṇi», досл. означает «держащий в руках колесо колесницы»-- <em>(rathacaraṇapāṇiḥ)</em> [был Твоей] стрелой <em>(śaraḥ iti)</em>, когда Ты --tvam-- <em>(te)</em> пожелал сжечь --didhakṣu-- <em>(didhakṣoḥ)</em> три <em>(tri)</em> города <em>(pura)</em>, [которые были как] трава <em>(tṛṇam)</em> [для Тебя]. [Тем не менее], в чём смысл <em>(kaḥ)</em> этого <em>(ayam)</em> громкого <em>(āḍambara)</em> действия <em>(vidhiḥ)</em>? [На самом деле] Мысли <em>(dhiyaḥ)</em> Господа <em>(prabhu)</em> не <em>(na khalu)</em> зависят <em>(tantrāḥ)</em> ни от чего <em>(para)</em>, [а] играют <em>(krīḍantyaḥ)</em> с объектами, находящимися в Его распоряжении <em>(vidheyaiḥ)</em>||18||</p><p>[/sect] [sect] [sans]हरिस्ते साहस्रं कमलबलिमाधाय पदयोर्यदेकोने तस्मिन्निजमुदहरन्नेत्रकमलम्। गतो भक्त्युद्रेकः परिणतिमसौ चक्रवपुषा त्रयाणां रक्षायै त्रिपुरहर जागर्ति जगताम्॥१९॥[/sans] [trans]Hariste sāhasraṁ kamalabalimādhāya padayoryadekone tasminnijamudaharannetrakamalam| Gato bhaktyudrekaḥ pariṇatimasau cakravapuṣā trayāṇāṁ rakṣāyai tripurahara jāgarti jagatām||19||[/trans] О Разрушитель <em>(hara)</em> трёх <em>(tri)</em> городов <em>(pura)</em>! Хари --т.e. Viṣṇu-- <em>(hariḥ)</em>, положив <em>(ādhāya)</em> <em>(своё)</em> подношение <em>(balim)</em> из тысячи <em>(sāhasram)</em> лотосов <em>(kamala)</em> к Твоим <em>(te)</em> стопам <em>(padayoḥ)</em>, <em>(заметил),</em> что <em>(yad)</em> одного [из лотосов] не хватало <em>(ekone)</em> в этом [подношении] <em>(tasmin)</em>. [И поэтому], он вырвал <em>(udaharat)</em> [один] из своих <em>(nijam)</em> лотосных глаз <em>(netrakamalam)</em>, [чтобы решить эту проблему]. [В результате], изобилие <em>(udrekaḥ)</em> <em>(его)</em> преданности <em>(bhakti)</em> <em>(было)</em> превращено <em>(gataḥ... pariṇatim)</em> <em>(Тобою)</em> в то <em>(asau)</em> прекрасное <em>(vapuṣā)</em> Колесо [известное как «Sudarśana»] <em>(cakra)</em>, которое с бдительностью <em>(jāgarti)</em> защищает <em>(rakṣāyai)</em> три <em>(trayāṇām)</em> мира <em>(jagatām)</em>||19||</p><p>[/sect] [sect] [sans]क्रतौ सुप्ते जाग्रत्त्वमसि फलयोगे क्रतुमतां क्व कर्म प्रध्वस्तं फलति पुरुषाराधनमृते। अतस्त्वां सम्प्रेक्ष्य क्रतुषु फलदानप्रतिभुवं श्रुतौ श्रद्धां बद्ध्वा दृढपरिकरः कर्मसु जनः॥२०॥[/sans] [trans]Kratau supte jāgrattvamasi phalayoge kratumatāṁ kva karma pradhvastaṁ phalati puruṣārādhanamṛte| Atastvāṁ samprekṣya kratuṣu phaladānapratibhuvaṁ śrutau śraddhāṁ baddhvā dṛḍhaparikaraḥ karmasu janaḥ||20||[/trans] Когда жертвоприношение --kratu-- <em>(kratau)</em> заканчивается --досл. «засыпает»-- <em>(supte)</em>, Ты <em>(tvam)</em> продолжаешь <em>(asi)</em> бодрствовать <em>(jāgrat)</em>, чтобы вознаградить <em>(phalayoge)</em> приносящего жертву <em>(kratumatām)</em>. Как <em>(kva)</em> ритуал жертвоприношения <em>(karma)</em>, который закончился <em>(pradhvastam)</em> может принести плоды <em>(phalati)</em> без <em>(ṛte)</em> поклонения <em>(ārādhanam)</em> Пуруше или Верховной Личности -- Шиве-- <em>(puruṣa)</em>? По этой причине <em>(atas)</em>, осознав <em>(samprekṣya)</em>, что Ты [являешься] <em>(tvām)</em> дарующим плоды <em>(phala-dānapratibhuvam)</em> в жертвоприношениях <em>(kratuṣu)</em>, и обладая <em>(baddhvā)</em> верою <em>(śraddhām)</em> в Шрути --т.e. в Веды-- <em>(śrutau)</em>, люди <em>(janaḥ)</em> решительно <em>(dṛḍha)</em> выполняют <em>(parikaraḥ)</em> обряды жертвоприношения <em>(karmasu)</em>||20||</p><p>[/sect] [sect] [sans]क्रियादक्षो दक्षः क्रतुपतिरधीशस्तनुभृतामृषीणामार्त्विज्यं शरणद सदस्याः सुरगणाः। क्रतुभ्रंशस्त्वत्तः क्रतुफलविधानव्यसनिनो ध्रुवं कर्तुः श्रद्धाविधुरमभिचाराय हि मखाः॥२१॥[/sans] [trans]Kriyādakṣo dakṣaḥ kratupatiradhīśastanubhṛtāmṛṣīṇāmārtvijyaṁ śaraṇada sadasyāḥ suragaṇāḥ| Kratubhraṁśastvattaḥ kratuphalavidhānavyasanino dhruvaṁ kartuḥ śraddhāvidhuramabhicārāya hi makhāḥ||21||[/trans] О Дарующий <em>(da)</em> убежище <em>(śaraṇa)</em>! Ты --tvam-- <em>(tvattaḥ)</em>, обожающий <em>(vyasaninaḥ)</em> постоянно <em>(dhruvam)</em> даровать <em>(vidhāna)</em> плоды <em>(phala)</em> жертвоприношений <em>(kratu)</em>, испортил --ababhraṁśas или abhraṁśayas-- <em>(bhraṁśaḥ)</em> [то известное] жертвоприношение <em>(kratu)</em>, [в котором] <em>Dakṣa</em> -- отец <em>Satī</em>, первой жены Шивы-- <em>(dakṣaḥ)</em>, эксперт <em>(dakṣaḥ)</em> в ритуалах жертвоприношений <em>(kriyā)</em> и господин <em>(adhīśaḥ)</em> всех существ, наделённых <em>(bhṛtām)</em> телом <em>(tanu)</em>, выполнял роль приносящего жертву <em>(kratupatiḥ)</em>. [В свою очередь] роль «ṛtvij» --жрецов-- <em>(ārtvijyam)</em> исполнялась [самими] ведическими Мудрецами --Ṛṣi-- <em>(ṛṣīṇām)</em>, [в то время как] полки <em>(gaṇāḥ)</em> богов <em>(sura)</em> [служили] верховными жрецами <em>(sadasyāḥ)</em>. Несомненно <em>(hi)</em>, жертвоприношения <em>(makhāḥ)</em>, [выполненные] для очарования [других] <em>(abhicārāya)</em>, нежелательны <em>(vidhuram)</em> для веры <em>(śraddhā)</em> исполняющего их <em>(kartuḥ)</em>||21||</p><p>[/sect] [sect] [sans]प्रजानाथं नाथ प्रसभमभिकं स्वां दुहितरं गतं रोहिद्भूतां रिरमयिषुमृष्यस्य वपुषा। धनुष्पाणेर्यातं दिवमपि सपत्राकृतममुं त्रसन्तं तेऽद्यापि त्यजति न मृगव्याधरभसः॥२२॥[/sans] [trans]Prajānāthaṁ nātha prasabhamabhikaṁ svāṁ duhitaraṁ gataṁ rohidbhūtāṁ riramayiṣumṛṣyasya vapuṣā| Dhanuṣpāṇeryātaṁ divamapi sapatrākṛtamamuṁ trasantaṁ te&#39;dyāpi tyajati na mṛgavyādharabhasaḥ||22||[/trans]</p><p>О Господин <em>(nātha)</em>! Твоя <em>(te)</em> мощная ярость <em>(rabhasaḥ)</em> в форме охотника <em>(mṛgavyādha)</em> даже сейчас <em>(adya-api)</em> не <em>(na)</em> покидает <em>(tyajati)</em> того <em>(amum)</em> господа <em>(nātham)</em> <em>(всех)</em> живых существ <em>(prajā)</em> --т.e. Брахму, или Создателя, из известной триады--, который был ранен <em>(sapatrā-kṛtam)</em> [стрелами вышеупомянутого] охотника с луком в руках <em>(dhanuṣpāṇeḥ)</em> [и] убежал <em>(yātam)</em> даже <em>(api)</em> на небеса <em>(divam)</em> в страхе [Тебя] <em>(trasantam)</em>. [Всё это произошло из-за того, что <em>Brahmā</em>] был охвачен <em>(gatam)</em> невероятной <em>(prasabham)</em> похотью <em>(abhikam)</em> по отношению к своей собственной <em>(svām)</em> дочери <em>(duhitaram)</em>. [Он принял] форму --vapus-- <em>(vapuṣā)</em> белоногой антилопы <em>(ṛṣyasya)</em>, чтобы овладеть [ею] <em>(riramayiṣum)</em> [и тогда она] стала <em>(bhūtām)</em> красным оленем <em>(rohit)</em>, [чтобы улететь от него]||22||</p><p>[/sect] [sect] [sans]स्वलावण्याशंसा धृतधनुषमह्नाय तृणवत्पुरः प्लुष्टं दृष्ट्वा पुरमथन पुष्पायुधमपि। यदि स्त्रैणं देवी यमनिरत देहार्धघटनादवैति त्वामद्धा बत वरद मुग्धा यवतयः॥२३॥[/sans] [trans]Svalāvaṇyāśaṁsā dhṛtadhanuṣamahnāya tṛṇavatpuraḥ pluṣṭaṁ dṛṣṭvā puramathana puṣpāyudhamapi| Yadi straiṇaṁ devī yamanirata dehārdhaghaṭanādavaiti tvāmaddhā bata varada mugdhā yuvatayaḥ||23||[/trans] О Разрушитель <em>(mathana)</em> [трёх] миров <em>(pura)</em>! Если <em>(yadi)</em> богиня <em>(Pārvatī)</em> <em>(devī)</em>, <em>(чья)</em> надежда <em>(āśaṁsā)</em> основана на ее собственной <em>(sva)</em> красоте и очаровании <em>(lāvaṇya)</em>, даже <em>(api)</em> в прошлом <em>(puras)</em> увидев <em>(dṛṣṭvā)</em> <em>(как)</em> Puṣpāyudha --досл. «цвето-рукий», эпитет Каамадевы, бога любви-- <em>(puṣpāyudham)</em>, оснащенный луком <em>(dhṛtadhanuṣam)</em> [был] немедленно <em>(ahnāya)</em> испепелён <em>(pluṣṭam)</em> <em>(Тобой)</em> подобно <em>(vat)</em> травинке <em>(tṛṇa)</em>, [всё ещё] считает <em>(avaiti)</em>, что Ты <em>(tvām)</em> управляем женщиной <em>(straiṇam)</em>, о Ты, посвящающий себя <em>(nirata)</em> [разному роду] ограничений <em>(yama)</em>! Поскольку [она] занимает <em>(ghaṭanāt)</em> половину <em>(ardha)</em> [Твоего] тела <em>(deha)</em>... [увы], о <em>(bata)</em> Дарующий <em>(da)</em> милость <em>(vara)</em>, молодые женщины <em>(yuvatayaḥ)</em> определённо <em>(addhā)</em> неопытны и просты <em>(mugdhāḥ)</em>!||23||[/trans]</p><p>[/sect] [sect] [sans]श्मशानेष्वाक्रीडा स्मरहर पिशाचाः सहचराश्चिताभस्मालेपः स्रगपि नृकरोटीपरिकरः। अमाङ्गल्यं शीलं तव भवतु नामैवमखिलं तथापि स्मर्तॄणां वरद परमं मङ्गलमसि॥२४॥[/sans] [trans]Śmaśāneṣvākrīḍā smarahara pīśācāḥ sahacarāścitābhasmālepaḥ sragapi nṛkaroṭīparikaraḥ| Amāṅgalyaṁ śīlaṁ tava bhavatu nāmaivamakhilaṁ tathāpi smartṝṇāṁ varada paramaṁ maṅgalamasi||24||[/trans] О Разрушитель <em>(hara)</em> Смары --т.e. Каамадевы, бога любви-- <em>(smara)</em>! <em>(Твоей)</em> площадкой для игр <em>(ākrīḍā)</em> [является] крематорий <em>(śmaśāneṣu)</em>, <em>(а)</em> Piśāca --вид демонов-- <em>(piśācāḥ)</em> <em>(Твои)</em> спутники <em>(sahacarāḥ)</em>. <em>(Ты)</em> наносишь <em>(ālepaḥ)</em> пепел <em>(bhasma)</em> похоронных костров [на Свое собственное тело] <em>(citā)</em> <em>(и)</em> даже <em>(api)</em> [носишь] гирлянду <em>(srak)</em> [из] множества <em>(parikaraḥ)</em> человеческих <em>(nṛ)</em> черепов <em>(karoṭī)</em>. Поэтому <em>(evam)</em>, <em>(пусть)</em> всё <em>(akhilam)</em> Твоё <em>(tava)</em> поведение <em>(śīlam)</em> будет <em>(bhavatu)</em> названо <em>(nāma)</em> «неблагоприятным» <em>(amāṅgalyam)</em>!... Тем не менее <em>(tathā-api)</em>, о Дарующий <em>(da)</em> милость <em>(vara)</em>, Ты <em>(asi)</em> Высшее <em>(paramam)</em> Благосостояние <em>(maṅgalam)</em> для тех, кто помнит [Тебя]! <em>(smartṝṇām)</em>||24||</p><p>[/sect] [sect] [sans]मनः प्रत्यक्चित्ते सविधमवधायात्तमरुतः प्रहृष्यद्रोमाणः प्रमदसलिलोत्सङ्गितदृशः। यदालोक्याह्लादं ह्रद इव निमज्ज्यामृतमये दधत्यन्तस्तत्त्वं किमपि यमिनस्तत् किल भवान्॥२५॥[/sans] [trans]Manaḥ pratyakcitte savidhamavadhāyāttamarutaḥ prahṛṣyadromāṇaḥ pramadasalilotsaṅgitadṛśaḥ| Yadālokyāhlādaṁ hrada iva nimajjyāmṛtamaye dadhatyantastattvaṁ kimapi yaminastat kila bhavān||25||[/trans] Погрузив <em>(avadhāya)</em> ум <em>(manas)</em> в Высшее Я <em>(pratyakcitte)</em>, согласно наставлениям писаний <em>(savidham)</em>, <em>(и)</em> контролируя <em>(ātta)</em> дыхание <em>(marutaḥ)</em>, с глазами <em>(dṛśaḥ)</em> полными <em>(utsaṅgita)</em> слёз <em>(salila)</em>, [испытывая] Радость <em>(pramada)</em>, от которой встают дыбом <em>(prahṛṣyat)</em> волосы <em>(на из телах)</em> <em>(romāṇaḥ)</em>, обладающие самоконтролем [мудрецы] <em>(yaminaḥ)</em>, во время <em>(yadā)</em> созерцания <em>(ālokya)</em> Восторга <em>(āhlādam)</em> <em>(и)</em> погружаясь <em>(nimajjya)</em>, так сказать <em>(iva)</em>, в Озеро <em>(hrade)</em> из --mayaḥ-- <em>(maye)</em> Нектара <em>(amṛta)</em>, ухватывают -- т.е. «осознают»-- <em>(dadhati)</em> Внутренний <em>(antar)</em> Принцип <em>(tattvam)</em> в значительной степени <em>(kim-api)</em>. Ты <em>(bhavān)</em> определённо [являешься] <em>(kila)</em> тем [Внутренним Принципом] <em>(tad)</em>||25||</p><p>[/sect] [sect] [sans]त्वमर्कस्त्वं सोमस्त्वमसि पवनस्त्वं हुतवहस्त्वमापस्त्वं व्योम त्वमु धरणिरात्मा त्वमिति च। परिच्छिन्नामेवं त्वयि परिणता विभ्रतु गिरं न विद्मस्तत्तत्त्वं वयमिह तु यत्त्वं न भवसि॥२६॥[/sans] [trans]Tvamarkastvaṁ somastvamasi pavanastvaṁ hutavahastvamāpastvaṁ vyoma tvamu dharaṇirātmā tvamiti ca| Paricchinnāmevaṁ tvayi pariṇatā bibhratu giraṁ na vidmastattattvaṁ vayamiha tu yattvaṁ na bhavasi||26||[/trans] «Ты <em>(tvam)</em> — солнце <em>(arkaḥ)</em>; Ты <em>(tvam)</em>— луна <em>(somaḥ)</em>; Ты <em>(tvam)</em> являешься <em>(asi)</em> воздухом <em>(pavanaḥ)</em>; Ты <em>(tvam)</em> — огонь --«принимающий жертвоприношение»-- <em>(huta-vahaḥ)</em>; Ты <em>(tvam)</em> — вода <em>(āpaḥ)</em>; Ты <em>(tvam)</em> — пространство_ <em>(vyoma)</em>._ Ты <em>(tvam)</em> — во истину <em>(u)</em> земля <em>(dharaṇiḥ)</em> и <em>(ca)</em> Ты <em>(tvam)</em> — Высшее Я <em>(ātmā)</em>» --«iti» означает кавычки--. Итак <em>(evam)</em>, [пусть] те, кто претерпел изменения --мудрецы-- <em>(pariṇatāḥ)</em> трепетно хранят <em>(bibhratu)</em> ограниченные <em>(paricchinnām)</em> описания --досл. «слова»-- <em>(giram)</em> Тебя <em>(tvayi)</em>! Тем не менее <em>(tu)</em>, в этом мире <em>(iha)</em>, мы <em>(vayam)</em> не <em>(na)</em> знаем <em>(vidmaḥ)</em> той <em>(tad)</em> реальности <em>(tattvam)</em>, которой <em>(yad)</em> Ты <em>(tvam)</em> не являлся бы <em>(na bhavasi)</em>||26||</p><p>[/sect] [sect] [sans]त्रयीं तिस्रो वृत्तीस्त्रिभुवनमथो त्रीनपि सुरानकाराद्यैर्वर्णैस्त्रिभिरभिदधत्तीर्णविकृति। तुरीयं ते धाम ध्वनिभिरवरुन्धानमणुभिः समस्तं व्यस्तं त्वां शरणद गृणात्योमिति पदम्॥२७॥[/sans] [trans]Trayīṁ tisro vṛttīstribhuvanamatho trīnapi surānakārādyairvarṇaistribhirabhidadhattīrṇavikṛti| Turīyaṁ te dhāma dhvanibhiravarundhānamaṇubhiḥ samastaṁ vyastaṁ tvāṁ śaraṇada gṛṇātyomiti padam||27||[/trans] О Дарующий <em>(da)</em> убежище <em>(śaraṇa)</em>! Слово <em>(padam)</em> «Om» <em>(om-iti)</em> описывает <em>(gṛṇāti)</em> Тебя <em>(tvām)</em> отдельно <em>(vyastam)</em> с помощью [своих] трёх <em>(tribhiḥ)</em> букв <em>(varṇaiḥ)</em>, [состоящих из различных] форм <em>(ākāra)</em> и т.д. <em>(ādyaiḥ)</em>, [которые обозначают] три Веды <em>(trayīm)</em>, три <em>(tisras)</em> состояния [сознания] --т.e. бодрствование, сон и глубокий сон-- <em>(vṛttīḥ)</em>, три <em>(tri)</em> мира <em>(bhuvanam)</em>, а также <em>(atho... api)</em> три <em>(trīn)</em> бога <em>(surān)</em>. [Поэтому Ты] описываешься <em>(abhidadhat)</em> как <em>(та Реальность),</em> которая претерпела <em>(tīrṇa)</em> [множество] изменений <em>(vikṛti)</em>. [В свою очередь], с помощью [этих самых трёх] тонких <em>(anubhiḥ)</em> звуков --dhvani-- <em>(dhvanibhiḥ)</em>, [слово «Ом» описывает Тебя] в целом <em>(samastam)</em>, [так как] оно содержит <em>(avarundhānam)</em> Четвёртое [состояние сознания] --т.e. Свидетеля всех остальных состояний-- <em>(turīyam)</em>, [являющееся] Твоей <em>(te)</em> [Трансцендентальной] Обителью или Состоянием <em>(dhāma)</em>||27||</p><p>[/sect] [sect] [sans]भवः शर्वो रुद्रः पशुपतिरथोग्रः सहमहांस्तथा भीमेशानाविति यदभिधानाष्टकमिदम्। अमुष्मिन्प्रत्येकं प्रविचरति देव श्रुतिरपि प्रियायास्मै धाम्ने प्रविहितनमस्योऽस्मि भवते॥२८॥[/sans] [trans]Bhavaḥ śarvo rudraḥ paśupatirathograḥ sahamahāṁstathā bhīmeśānāviti yadabhidhānāṣṭakamidam| Amuṣminpratyekaṁ pravicarati deva śrutirapi priyāyāsmai dhāmne pravihitanamasyo&#39;smi bhavate||28||[/trans] «Бхава <em>(bhavaḥ)</em>, Шарва <em>(śarvaḥ)</em>, Рудра <em>(rudraḥ)</em>, Пашупати <em>(paśupatiḥ)</em>, а также <em>(atha)</em> Угра <em>(ugraḥ)</em> и <em>(saha)</em> Махаадева <em>(mahān)</em> и <em>(tathā)</em> Бхиима <em>(bhīma)</em> и Иишаана <em>(īśānau)</em>» --«iti» означает кавычки--. Это <em>(idam)</em> – группа, состоящая из восьми <em>(aṣṭakam)</em> имён <em>(abhidhāna)</em> того <em>(Шивы)</em> <em>(yad)</em>. О Бог <em>(deva)</em>! Даже если <em>(api)</em> Шрути --Веды-- <em>(śrutiḥ)</em> тщательно исследуют <em>(pravicarati)</em> каждое из них <em>(pratyekam)</em> в этой <em>(группе)</em> <em>(amuṣmin)</em>, Я преклоняюсь <em>(pravihita-namasyaḥ asmi)</em> перед этой <em>(asmai)</em> дорогой <em>(priyāya)</em> [Трансцендентальной] Обителью или [Высшим] Состоянием --dhāma-- <em>(dhāmne)</em>, [сутью которого являешься] Ты --bhavān-- <em>(bhavate)</em>||28||</p><p>[/sect] [sect] [sans]नमो नेदिष्ठाय प्रियदव दविष्ठाय च नमो नमः क्षोदिष्ठाय स्मरहर महिष्ठाय च नमः। नमो वर्षिष्ठाय त्रिनयन यविष्ठाय च नमो नमः सर्वस्मै ते तदिदमितिसर्वाय च नमः॥२९॥[/sans] [trans]Namo nediṣṭhāya priyadava daviṣṭhāya ca namo namaḥ kṣodiṣṭhāya smarahara mahiṣṭhāya ca namaḥ| Namo varṣiṣṭhāya trinayana yaviṣṭhāya ca namo namaḥ sarvasmai te tadidamitisarvāya ca namaḥ||29||[/trans] О Ты, обожающий <em>(priya)</em> огонь <em>(dava)</em>! Приветствия <em>(namas)</em> Самому Близкому <em>(nediṣṭhāya)</em> и <em>(ca)</em> приветствия <em>(namas)</em> Самому Далёкому <em>(daviṣṭhāya)</em>. О Разрушитель <em>(hara)</em> Каамадевы [— бога любви] <em>(smara)</em>! Приветствия <em>(namas)</em> Самому Малому <em>(kṣodiṣṭhāya)</em>, а также <em>(ca)</em> приветствия <em>(namas)</em> Самому Великому <em>(mahiṣṭhāya)</em>. О Трехглазый [Шива] <em>(trinayana)</em>! Приветствия <em>(namas)</em> Старейшему <em>(varṣiṣṭhāya)</em> и <em>(ca)</em> приветствия <em>(namas)</em> Самому Молодому <em>(yaviṣṭhāya)</em>. Приветствия <em>(namas)</em> Тебе <em>(te)</em>, тому, кто является всем --sarva-- <em>(sarvasmai)</em>, <em>а также</em> <em>(ca)</em> приветствия <em>(namas)</em> Сарве --эпитет Шивы-- <em>(sarvāya)</em>, [так как он является в форме] «того <em>(tad)</em> и сего <em>(idam-iti)</em>» --Шива зовётся «Сарвой», потому что Он — этот человек и тот, это животное и то, этот объект и тот и т.д... Он всё и все--||29||</p><p>[/sect] [sect] [sans]बहलरजसे विश्वोत्पत्तौ भवाय नमो नमः प्रबलतमसे तत्संहारे हराय नमो नमः। जनसुखकृते सत्त्वोद्रिक्तौ मृडाय नमो नमः प्रमहसि पदे निस्त्रैगुण्ये शिवाय नमो नमः॥३०॥[/sans] [trans]Bahalarajase viśvotpattau bhavāya namo namaḥ prabalatamase tatsaṁhāre harāya namo namaḥ| Janasukhakṛte sattvodriktau mṛḍāya namo namaḥ pramahasi pade nistraiguṇye śivāya namo namaḥ||30||[/trans] Множество приветствий <em>(namas namas)</em> Бхаве -- эпитет Шивы, означающий «существование»-- <em>(bhavāya)</em>, [являющемуся в форме] <em>Viśvotpatti</em> --досл. «тот, из кого происходит вселенная», то есть Brahmā, Создатель-- <em>(viśvotpattau)</em>, [в котором присутствует] огромное количество <em>(bahala)</em> Rajoguṇa --т.e. качества «раджас»-- <em>(rajase)</em>. Я приветствую вновь и вновь <em>(namas namas)</em> Хару --эпитет Шивы, означающий «Разрушитель»-- <em>(harāya)</em>, [являющемуся в форме] <em>Tatsaṁhāra</em> --досл. «тот, кто разрушает эту [вселенную]», то есть, Рудра, Разрушитель-- <em>(tatsaṁhāre)</em> [в котором присутствует] обильное количество <em>(prabala)</em> Tamoguṇa --т.e. качества «тамас»-- <em>(tamase)</em>. Приветствую вновь и вновь <em>(namas namas)</em> Мриду --эпитет Шивы, означающий «сострадательный» или «милостивый»-- <em>(mṛḍāya)</em>, [являющегося в форме] <em>Sattvodrikti</em> --досл. «тот, в ком обильна Sattvaguṇa или качество «саттва», то есть, Вишну, Поддержателя-- <em>(sattvodriktau)</em> во имя <em>(kṛte)</em> счастья <em>(sukha)</em> [всех] живых существ <em>(jana)</em>. Множество приветствий <em>(namas namas)</em> Шиве --досл. «Благоприятный»-- <em>(śivāya)</em>, [являющемуся в форме] сияющего <em>(pramahasi)</em> состояния <em>(pade)</em>, не наделённого гунами или качествами <em>(nistraiguṇye)</em> ||30||</p><p>[/sect] [sect] [sans]कृशपरिणति चेतः क्लेशवश्यं क्व चेदं क्व च तव गुणसीमोल्लङ्घिनी शश्वदृद्धिः। इति चकितममन्दीकृत्य मां भक्तिराधाद्वरद चरणयोस्ते वाक्यपुष्पोहारम्॥३१॥[/sans] [trans]Kṛśapariṇati cetaḥ kleśavaśyaṁ kva cedaṁ kva ca tava guṇasīmollaṅghinī śaśvadṛddhiḥ| Iti cakitamamandīkṛtya māṁ bhaktirādhādvarada caraṇayoste vākyapuṣpopahāram||31||[/trans] Как <em>(kva ca)</em> слабо <em>(kṛśa)</em> развит <em>(pariṇati)</em> этот <em>(idam)</em> ум <em>(cetas)</em>, управляемый <em>(vaśyam)</em> Клешами --т.e. широко известными пятью напастями: невежеством, эго, привязанностью, отвращением и страхом смерти-- <em>(kleśa)</em>. И как <em>(kva ca)</em> бесконечно и вечно <em>(śaśvat)</em> Твоё <em>(tava)</em> Процветание <em>(ṛddhiḥ)</em>, выходящее за <em>(ullaṅghinī)</em> границу <em>(sīmā)</em>, [обозначенную тремя] гунами или качествами <em>(guṇa)</em>! Таким образом <em>(iti)</em>, [хотя я и] очень <em>(amandīkṛtya)</em> напуган <em>(cakitam)</em> <em>(этим)</em>, о Дарующий <em>(da)</em> милость <em>(vara)</em>, преданность <em>(bhaktiḥ)</em> заставила <em>(ādhāt)</em> меня <em>(mām)</em> преподнести <em>(upahāram)</em> цветы <em>(puṣpa)</em> [в виде] слов <em>(vākya)</em> к Твоим <em>(te)</em> стопам <em>(caraṇayoḥ)</em> ||31||</p><p>[/sect] [sect] [sans]असितगिरिसमं स्यात्कज्जलं सिन्धुपात्रे सुरतरुवरशाखा लेखनी पत्रमुर्वी। लिखति यदि गृहीत्वा शारदा सर्वकालं तदपि तव गुणानामीश पारं न याति॥३२॥[/sans] [trans]Asitagirisamaṁ syātkajjalaṁ sindhupātre surataruvaraśākhā lekhanī patramurvī| Likhati yadi gṛhītvā śāradā sarvakālaṁ tadapi tava guṇānāmīśa pāraṁ na yāti||32||[/trans] [Если бы определённое количество] ламповой сажи -- используемой как чернила-- <em>(kajjalam)</em>, соответствующее <em>(samam)</em> черной <em>(asita)</em> горе <em>(giri)</em>, было бы <em>(syāt)</em> <em>(налито в)</em> океан <em>(sindhu)</em>, выполняющий роль сосуда --т.e. чернильницы-- <em>(pātre)</em>, <em>(и если бы)</em> ветвь <em>(śākhā)</em> лучшего <em>(vara)</em> дерева <em>(taru)</em> богов <em>(sura)</em> --т.e. прославленного Kalpavṛkṣa-- [использовалась бы] в виде ручки <em>(lekhanī)</em>, <em>(а сама</em>_)_ земля <em>(urvī)</em> — [в виде] листа для письма <em>(patram)</em>, [и] если бы <em>(yadi)</em> Śāradā --т.e. «Sarasvatī», река-богиня, обычно ассоциируемая с красноречием и образованием-- <em>(śāradā)</em>, взяв [эти принадлежности] <em>(gṛhītvā)</em>, писала бы <em>(likhati)</em> вечно <em>(sarvakālam)</em>, даже <em>(api)</em> эта [восхитительная метафора] <em>(tad)</em>, о Бог <em>(īśa)</em>, не <em>(na)</em> достигла бы <em>(yāti)</em> конца <em>(pāram)</em> Твоих <em>(tava)</em> положительных качеств <em>(guṇānām)</em> --другими словами, все качества Шивы не могут быть описаны, даже если такой великий персонаж, как сама Sarasvatī вечно записывала бы их, используя вышеупомянутые принадлежности--||32||</p><p>[/sect] [sect] [sans]असुरसुरमुनीन्द्रैरर्चितस्येन्दुमौलेर्ग्रथितगुणमहिम्नो निर्गुणस्येश्वरस्य। सकलगणवरिष्ठः पुष्पदन्ताभिधानो रुचिरमलघुवृत्तैः स्तोत्रमेतच्चकार॥३३॥[/sans] [trans]Asurasuramunīndrairarcitasyendumaulergrathitaguṇamahimno nirguṇasyeśvarasya| Sakalagaṇavariṣṭhaḥ puṣpadantābhidhāno ruciramalaghuvṛttaiḥ stotrametaccakāra||33||[/trans] [Гандхарва или небесный музыкант] по имени <em>(abhidhānaḥ)</em> Puṣpadanta --досл. «с зубами из цветов»-- <em>(puṣpadanta)</em>, лучший <em>(variṣṭhaḥ)</em> из всей <em>(sakala)</em> группы слуг Шивы <em>(gaṇa)</em>, сочинил <em>(cakāra)</em> этот <em>(etad)</em> прекрасный <em>(ruciram)</em> гимн <em>(stotram)</em>, наделённый длинными <em>(alaghu)</em> мерами стихосложения <em>(vṛttaiḥ)</em>, <em>(в честь)</em> Господа <em>(īśvarasya)</em>, который носит луну <em>(indu)</em> на Своей голове --mauli-- <em>(mauleḥ)</em> и которому поклоняются <em>(arcitasya)</em> Индра --indreṇa-- <em>(indraiḥ)</em>, мудрецы <em>(muni)</em>, боги <em>(sura)</em> и демоны <em>(asura)</em>, и чьё Величие <em>(mahimnaḥ)</em> состоит из <em>(бесконечных)</em> качеств <em>(guṇa)</em>, нанизанных вместе [на одну нить, подобно бусинам в ожерелье] <em>(grathita)</em>, [хотя он полностью] лишён любых качеств --nirguṇa-- <em>(nirguṇasya)</em> ||33||</p><p>[/sect] [sect] [sans]अहरहरनवद्यं धूर्जटेः स्तोत्रमेतत्पठति परमभक्त्या शुद्धचित्तः पुमान् यः। स भवति शिवलोके रुद्रतुल्यस्तथाऽत्र प्रचुरतरधनायुःपुत्रवान्कीर्तिमांश्च॥३४॥[/sans] [trans]Aharaharanavadyaṁ dhūrjaṭeḥ stotrametatpaṭhati paramabhaktyā śuddhacittaḥ pumān yaḥ| Sa bhavati śivaloke rudratulyastathā&#39;tra pracurataradhanāyuḥputravānkīrtimāṁśca||34||[/trans] Человеческое существо <em>(pumān)</em> с чистым умом <em>(śuddha-cittaḥ)</em>, которое <em>(yaḥ)</em> _с величайшей <em>(parama)</em> преданностью <em>(bhaktyā)</em> день за днём <em>(ahar-ahar)</em> безупречно <em>(anavadyam)</em> повторяет <em>(paṭhati)</em> этот <em>(etad)</em> гимн <em>(stotram)</em> (в честь) <em>Dhūrjaṭi</em> --эпитет Шивы, означающий «с грузом из спутанных локонов»-- <em>(dhūrjaṭeḥ)</em>, становится <em>(saḥ bhavati)</em> идентичным <em>(tulyaḥ)</em> Рудре --т.e. Шиве-- <em>(rudra)</em> в мире Шивы <em>(śiva-loke)</em> [после смерти]. Также <em>(tathā)</em>, [он становится] известным <em>(kīrtimān)</em>, многодетным <em>(putravān)</em>, [наслаждается долгой] жизнью <em>(āyus)</em> и <em>(ca)</em> более <em>(tara)</em> обильным <em>(pracura)</em> богатством <em>(dhana)</em> в этом мире <em>(atra)</em> ||34||</p><p>[/sect] [sect] [sans]दीक्षा दानं तपस्तीर्थं योगयागादिकाः क्रियाः। महिम्नः स्तव पाठस्य कलां नार्हन्ति षोडशीम्॥३५॥[/sans] [trans]Dīkṣā dānaṁ tapastīrthaṁ yogayāgādikāḥ kriyāḥ| Mahimnaḥ stavapāṭhasya kalāṁ nārhanti ṣoḍaśīm||35||[/trans] Инициация <em>(dīkṣā)</em>, благотворительность <em>(dānam)</em>, аскезы <em>(tapas)</em>, паломничество <em>(tīrtham)</em> <em>(и подобная)</em> деятельность <em>(kriyāḥ)</em>, [такая как] Йога <em>(yoga)</em>, жертвоприношение <em>(yāga)</em> и т.д., <em>(ādikāḥ)</em> не <em>(na)</em> стоит <em>(arhanti)</em> [даже] шестнадцатой <em>(ṣoḍaśīm)</em> части <em>(kalām)</em> [того, что стоит] повторение <em>(pāṭhasya)</em> [этого] гимна <em>(stava)</em> Величия <em>(mahimnaḥ)</em> Шивы||35||</p><p>[/sect] [sect] [sans]आसमाप्तमिदं स्तोत्रं पुण्यं गन्धर्वभाषितम्। अनौपम्यं मनोहारि शिवमीश्वरवर्णनम्॥३६॥[/sans] [trans]Āsamāptamidaṁ stotraṁ puṇyaṁ gandharvabhāṣitam| Anaupamyaṁ manohāri śivamīśvaravarṇanam||36||[/trans] Этот <em>(idam)</em> священный <em>(puṇyam)</em> гимн <em>(stotram)</em>, произнесённый <em>(bhāṣitam)</em> [известным] божественным музыкантом [по имени Puṣpadanta] <em>(gandharva)</em>, [содержащий] непревзойдённые <em>(anaupamyam)</em>, восхитительные <em>(manohāri)</em> и благоприятные <em>(śivam)</em> описания <em>(varṇanam)</em> Господа <em>(īśvara)</em>, заканчивается <em>(āsamāptam)</em> ||36||</p><p>[/sect] [sect] [sans]महेशान्नापरो देवो महिम्नो नापरा स्तुतिः। अघोरान्नापरो मन्त्रो नास्ति तत्त्वं गुरोः परम्॥३७॥[/sans] [trans]Maheśānnāparo devo mahimno nāparā stutiḥ| Aghorānnāparo mantro nāsti tattvaṁ guroḥ param||37||[/trans] Не существует <em>(na)</em> бога <em>(devaḥ)</em> выше <em>(aparaḥ)</em> Махеши --эпитет Шивы, означающий «великий Господь»-- <em>(maheśāt)</em>, не существует <em>(na)</em> восхваляющего гимна <em>(stutiḥ)</em> выше <em>(aparā)</em> [этого] «Śivamahimnaḥ stotram» <em>(mahimnaḥ)</em>. Не существует <em>(na)</em> Мантры --священного слова-- <em>(mantraḥ)</em> выше <em>(aparaḥ)</em> «Aghora» --эпитет Шивы, означающий «не ужасающий»-- <em>(aghora)</em> [и] нет <em>(na asti)</em> принципа <em>(tattvam)</em> выше <em>(param)</em> Гуру --в смысле пятого «kṛtya» или действия Шивы, которое дарует божественную Милость ограниченному существу-- <em>(guroḥ)</em> ||37||</p><p>[/sect] [sect] [sans]कुसुमदशननामा सर्वगन्धर्वराजः शिशुशशधरमौलेर्देवदेवस्य दासः। स खलु निजमहिम्नो भ्रष्ठ एवास्य रोषात्स्तवनमिदमकार्षीद्दिव्यदिव्यं महिम्नः॥३८॥[/sans] [trans]Kusumadaśananāmā sarvagandharvarājaḥ śiśuśaśadharamaulerdevadevasya dāsaḥ| Sa khalu nijamahimno bhraṣṭa evāsya roṣātstavanamidamakārṣīddivyadivyaṁ mahimnaḥ||38||[/trans] Царь <em>(rājaḥ)</em> всех <em>(sarva)</em> божественных музыкантов <em>(gandharva)</em> по имени <em>(nāmā)</em> <em>Kusumadaśana</em> --синоним термину «Puṣpadanta», т.e. «с зубами из цветов», так как «kusuma» = puṣpa (цветок) и «daśana» = danta (зуб)-- <em>(kusumadaśana)</em> [является] слугой <em>(dāsaḥ)</em> Бога <em>(devasya)</em> богов <em>(deva)</em>, носящего месяц _(śiśu _<em>śaśadhara)</em> на Своей голове --mauli-- <em>(mauleḥ)</em>. Он --Puṣpadanta-- <em>(saḥ)</em> определённо <em>(khalu... eva)</em> пал <em>(bhraṣṭaḥ)</em> из своего <em>(nija)</em> величия <em>(mahimnaḥ)</em> из-за ярости <em>(roṣāt)</em> Шивы <em>(asya)</em> --так как Puṣpadanta нечаянно наступил на траву, священную для Шивы-- [и] сочинил <em>(akārṣīt)</em> этот <em>(idam)</em> прекрасный <em>(divya)</em> божественный <em>(divyam)</em> гимн восхваления <em>(stavanam)</em> <em>(в честь)</em> Величия [того самого Шивы] <em>(mahimnaḥ)</em>, [чтоб обрести Его милость]||38||</p><p>[/sect] [sect] [sans]सुरवरमुनिपूज्यं स्वर्गमोक्षैकहेतुं पठति यदि मनुष्यः प्राञ्जलिर्नान्यचेताः। व्रजति शिवसमीपं किन्नरैः स्तूयमानः स्तवनमिदममोघं पुष्पदन्तप्रणीतम्॥३९॥[/sans] [trans]Suravaramunipūjyaṁ svargamokṣaikahetuṁ paṭhati yadi manuṣyaḥ prāñjalirnānyacetāḥ| Vrajati śivasamīpaṁ kinnaraiḥ stūyamānaḥ stavanamidamamoghaṁ puṣpadantapraṇītam||39||[/trans] Если <em>(yadi)</em> человеческое существо <em>(manuṣyaḥ)</em>, чей ум <em>(cetāḥ)</em> полностью направлен в одну точку <em>(na-anya)</em>, повторяет <em>(paṭhati)</em>, сложив пустые ладони <em>(prāñjaliḥ)</em>, этот <em>(idam)</em> безупречный <em>(amogham)</em> гимн восхваления <em>(stavanam)</em>, написанный <em>(praṇītam)</em> Пушпадантой <em>(puṣpadanta)</em>, которому поклоняются <em>(pūjyam)</em> боги <em>(sura)</em> и лучшие <em>(vara)</em> мудрецы <em>(muni)</em>, и который является единственной <em>(eka)</em> причиной <em>(hetu)</em> небесного <em>(svarga)</em> Освобождения <em>(mokṣa)</em>, [тогда такая личность], восхваляемая <em>(stūyamānaḥ)</em> Киннарами --видом божественных существ-- <em>(kinnaraiḥ)</em>, направляется <em>(vrajati)</em> к <em>(samīpam)</em> Шиве <em>(śiva)</em> ||39||</p><p>[/sect] [sect] [sans]श्रीपुष्पदन्तमुखपङ्कजनिर्गतेन स्तोत्रेण किल्बिषहरेण हरप्रियेण। कण्ठस्थितेन पठितेन समाहितेन सुप्रीणितो भवति भूतपतिर्महेशः॥४०॥[/sans] [trans]Śrīpuṣpadantamukhapaṅkajanirgatena stotreṇa kilbiṣahareṇa harapriyeṇa| Kaṇṭhasthitena paṭhitena samāhitena suprīṇito bhavati bhūtapatirmaheśaḥ||40||[/trans] Maheśa --досл. «великий Господь»-- <em>(maheśaḥ)</em>, Господин <em>(patiḥ)</em> [всех] существ <em>(bhūta)</em>, остаётся <em>(bhavati)</em> доволен <em>(suprīṇitaḥ)</em> [повторением этого] гимна <em>(stotreṇa)</em>, произошедшего из --nirgata-- <em>(nirgatena)</em> лотосных уст <em>(mukha-paṅkaja)</em> Достопочтимого <em>(śrī)</em> Пушпаданты <em>(puṣpadanta)</em>, разрушающего --hara-- <em>(hareṇa)</em> грехи <em>(kilbiṣa)</em> <em>(и)</em> дорогого --priya-- <em>(priyeṇa)</em> Харе --Шиве-- <em>(hara)</em>, [будь] он заучен наизусть --kaṇṭhasthita-- <em>(kaṇṭhasthitena)</em> <em>(или)</em> повторяем --paṭhita-- <em>(paṭhitena)</em> [или просто] внимательно выслушан --samāhita-- <em>(samāhitena)</em> --другой вариант перевода: «[или просто] храним [дома]»--||40||</p><p>[/sect] [sect] [sans]इत्येषा वाङ्मयी पूजा श्रीमच्छङ्करपादयोः। अर्पिता तेन देवेशः प्रीयतां मे सदाशिवः॥४१॥[/sans] [trans]Ityeṣā vāṅmayī pūjā śrīmacchaṅkarapādayoḥ| Arpitā tena deveśaḥ prīyatāṁ me sadāśivaḥ||41||[/trans] Итак <em>(iti)</em>, это <em>(eṣā)</em> поклонение <em>(pūjā)</em>, состоящее <em>(mayī)</em> из слов <em>(vāk)</em>, предлагается <em>(arpitā)</em> стопам <em>(pādayoḥ)</em> Достопочтимого <em>(śrīmat)</em> <em>Шанкары</em> --эпитет Шивы, означающий «дарующий процветание, благотворный и т.д.»-- <em>(śaṅkara)</em>. С помощью этого [подношения] <em>(tena)</em>, [да будет] <em>Sadāśiva</em> --эпитет Шивы, означающий «вечно благоприятный»-- <em>(sadāśivaḥ)</em>, Господин <em>(īśa)</em> богов <em>(deva)</em>, доволен <em>(prīyatām)</em> мною <em>(me)</em>! ||41||</p><p>[/sect] [sect] [sans]यदक्षरं पदं भ्रष्टं मात्राहीनं च यद्भवेत्। तत्सर्वं क्षम्यतां देव प्रसीद परमेश्वर॥४२॥[/sans] [trans]Yadakṣaraṁ padaṁ bhraṣṭaṁ mātrāhīnaṁ ca yadbhavet| Tatsarvaṁ kṣamyatāṁ deva prasīda parameśvara||42||[/trans] Любой <em>(yad... yad)</em> слог <em>(akṣaram)</em> <em>(или)</em> слово <em>(padam)</em>, которое было <em>(bhavet)</em> пропущено <em>(bhraṣṭam)</em> или --досл. «и» -- <em>(ca)</em> произнесено не вовремя <em>(mātrā-hīnam)</em>, да простит <em>(kṣamyatām)</em> Бог <em>(deva)</em> всё <em>(sarva)</em> это <em>(tad)</em>. О Всевышний <em>(parama)</em> Господь <em>(īśvara)</em>, будь удовлетворён <em>(prasīda)</em>!||42||</p><p>[/sect] [sect] [sans]ॐ शान्तिः शान्तिः शान्तिः॥[/sans] [trans]Om̐ śāntiḥ śāntiḥ śāntiḥ||[/trans] Om̐ <em>(om̐)</em>, мир <em>(śāntiḥ)</em>, мир <em>(śāntiḥ)</em>, мир <em>(śāntiḥ)</em>.</p><p>[/sect]</p>',52);r.render=function(e,t,r,s,n,h){return a(),m("div",null,[i])};export default r;export{t as __pageData};
